1	"use client";
2	
3	import useSWR from "swr";
4	import Link from "next/link";
5	import {
6	  semanticReleases as srApi,
7	  projects as projectsApi,
8	  sources as sourcesApi,
9	  contextSources,
10	} from "@/lib/api/client";
11	import { useRouter } from "next/navigation";
12	import { StatusDot } from "@/components/ui/status-dot";
13	import { VersionChip } from "@/components/ui/version-chip";
14	import { SectionLabel } from "@/components/ui/section-label";
15	import { ProviderBadge } from "@/components/ui/provider-badge";
16	import { timeAgo } from "@/lib/format";
17	import { getPathSegment } from "@/lib/path";
18	import { useTranslation } from "@/lib/i18n/context";
19	import {
20	  ArrowLeft,
21	  Check,
22	  ExternalLink,
23	  Copy,
24	  ShieldAlert,
25	  BookOpen,
26	  Download,
27	} from "lucide-react";
28	
29	function getRiskColors(riskLevel?: string) {
30	  switch (riskLevel?.toUpperCase()) {
31	    case "CRITICAL":
32	      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
33	    case "HIGH":
34	      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
35	    case "MEDIUM":
36	      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
37	    case "LOW":
38	    default:
39	      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
40	  }
41	}
42	
43	function safeHostname(url: string): string {
44	  try {
45	    return new URL(url).hostname.replace("www.", "");
46	  } catch {
47	    return url;
48	  }
49	}
50	
51	function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
52	  const lower = url.toLowerCase();
53	  const filename = lower.split("/").pop() ?? "";
54	
55	  // Detect platform from common patterns in the URL or filename
56	  const platforms: [RegExp, string][] = [
57	    [/linux.*amd64|amd64.*linux/, "Linux x64"],
58	    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
59	    [/linux.*386|linux.*i386/, "Linux x86"],
60	    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
61	    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
62	    [/darwin|macos|osx/, "macOS"],
63	    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
64	    [/windows.*386|win32/, "Windows x86"],
65	    [/windows/, "Windows"],
66	  ];
67	
68	  // Check if this is a direct binary (archive or executable)
69	  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
70	
71	  if (isArchive) {
72	    for (const [pattern, label] of platforms) {
73	      if (pattern.test(filename) || pattern.test(url)) {
74	        return { label, isDirect: true };
75	      }
76	    }
77	    // Direct download but platform unknown — use filename
78	    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
79	    return { label: cleanName || safeHostname(url), isDirect: true };
80	  }
81	
82	  // Not a direct binary — generic link
83	  return { label: safeHostname(url), isDirect: false };
84	}
85	
86	export function SemanticReleaseDetail() {
87	  const { t } = useTranslation();
88	  // Read IDs from URL path — useParams() returns stale "0" in static export
89	  const projectId = getPathSegment(1); // /projects/{id}/semantic-releases/{srId}
90	  const srId = getPathSegment(3);
91	  const router = useRouter();
92	  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
93	  const { data: projectData } = useSWR(`project-${projectId}`, () =>
94	    projectsApi.get(projectId),
95	  );
96	  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
97	    srApi.getSources(srId),
98	  );
99	  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
100	    sourcesApi.listByProject(projectId),
101	  );
102	  const { data: contextSourcesData } = useSWR(
103	    `project-context-sources-${projectId}`,
104	    () => contextSources.list(projectId),
105	  );
106	
107	  if (isLoading) {
108	    return (
109	      <div className="flex justify-center py-20">
110	        <div
111	          className="text-[13px] text-text-muted"
112	          style={{ fontFamily: "var(--font-dm-sans)" }}
113	        >
114	          {t("sr.detail.loading")}
115	        </div>
116	      </div>
117	    );
118	  }
119	
120	  const sr = data?.data;
121	  if (!sr) {
122	    return (
123	      <div className="flex justify-center py-20">
124	        <div
125	          className="text-[13px] text-text-muted"
126	          style={{ fontFamily: "var(--font-dm-sans)" }}
127	        >
128	          {t("sr.detail.notFound")}
129	        </div>
130	      </div>
131	    );
132	  }
133	
134	  const project = projectData?.data;
135	  const releasesList = srSourcesData?.data ?? [];
136	  const sourcesList = sourcesData?.data ?? [];
137	  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
138	  const contextSourcesList = contextSourcesData?.data ?? [];
139	
140	  const handleDelete = async () => {
141	    if (!confirm(t("sr.detail.deleteConfirm"))) return;
142	    try {
143	      await srApi.delete(srId);
144	      router.push("/releases");
145	    } catch {
146	      alert(t("sr.detail.deleteFailed"));
147	    }
148	  };
149	
150	  const report = sr.report;
151	  const riskLevel = (report?.urgency ?? report?.risk_level)?.toUpperCase();
152	  const hasRiskOrUrgency = riskLevel || report?.urgency;
153	  const riskColors = getRiskColors(riskLevel);
154	
155	  const statusChecks = report?.status_checks ?? [];
156	  const downloadLinks = report?.download_links ?? [];
157	  const downloadCommands = report?.download_commands ?? [];
158	  const hasAvailabilitySection =
159	    statusChecks.length > 0 ||
160	    downloadLinks.length > 0 ||
161	    downloadCommands.length > 0;
162	
163	  return (
164	    <div className="fade-in mx-auto max-w-[760px]">
165	      {/* 1. Back link */}
166	      <button
167	        onClick={() => window.history.length > 1 ? router.back() : router.push("/releases")}
168	        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70 cursor-pointer"
169	        style={{
170	          fontFamily: "var(--font-dm-sans)",
171	          fontSize: "13px",
172	          color: "var(--text-secondary)",
173	        }}
174	      >
175	        <ArrowLeft size={14} />
176	        {t("sr.detail.back")}
177	      </button>
178	
179	      {/* 2. Project byline */}
180	      {project?.name && (
181	        <p
182	          className="mb-1 text-[13px] italic text-text-muted"
183	          style={{ fontFamily: "var(--font-raleway)" }}
184	        >
185	          {project.name}
186	        </p>
187	      )}
188	
189	      {/* 3. Version heading */}
190	      <h1
191	        className="text-[42px] font-bold tracking-tight text-foreground leading-[1.1]"
192	        style={{ fontFamily: "var(--font-raleway)" }}
193	      >
194	        {sr.version}
195	      </h1>
196	
197	      {/* 4. Subject line */}
198	      {report?.subject && (
199	        <p
200	          className="mt-2 text-[20px] leading-[1.4] text-secondary-foreground"
201	          style={{ fontFamily: "var(--font-dm-sans)" }}
202	        >
203	          {report.subject}
204	        </p>
205	      )}
206	
207	      {/* 5. Meta line */}
208	      <div
209	        className="mt-3 flex items-center gap-2 text-[13px] text-text-secondary"
210	        style={{ fontFamily: "var(--font-dm-sans)" }}
211	      >
212	        <StatusDot status={sr.status} />
213	        <span className="flex-1">
214	          {sr.status}
215	          {sr.completed_at && ` \u00b7 ${t("sr.detail.generated")} ${timeAgo(sr.completed_at)}`}
216	        </span>
217	        <button
218	          onClick={handleDelete}
219	          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
220	          style={{ fontFamily: "var(--font-dm-sans)" }}
221	        >
222	          {t("sr.detail.delete")}
223	        </button>
224	      </div>
225	
226	      {/* 6. Divider */}
227	      <hr
228	        className="my-8 border-0"
229	        style={{ borderTop: "1px solid var(--border)" }}
230	      />
231	
232	      {/* 7. Error state */}
233	      {sr.error && (
234	        <div
235	          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
236	          style={{
237	            border: "1px solid #fca5a5",
238	            backgroundColor: "#fef2f2",
239	            fontFamily: "var(--font-dm-sans)",
240	          }}
241	        >
242	          {sr.error}
243	        </div>
244	      )}
245	
246	      {report && (
247	        <div className="space-y-10">
248	          {/* 8. Risk & Urgency Banner */}
249	          {hasRiskOrUrgency && (
250	            <div
251	              className="rounded-md px-4 py-4"
252	              style={{
253	                backgroundColor: riskColors.bg,
254	                borderLeft: `3px solid ${riskColors.border}`,
255	              }}
256	            >
257	              <div className="flex items-start gap-3">
258	                <ShieldAlert
259	                  className="h-5 w-5 mt-0.5 shrink-0"
260	                  style={{ color: riskColors.border }}
261	                />
262	                <div className="flex-1">
263	                  <div className="flex items-center gap-2 mb-1">
264	                    {riskLevel && (
265	                      <span
266	                        className="rounded px-1.5 py-0.5 text-[11px] font-bold uppercase"
267	                        style={{
268	                          backgroundColor: riskColors.border,
269	                          color: "#ffffff",
270	                        }}
271	                      >
272	                        {riskLevel} {t("sr.detail.urgency")}
273	                      </span>
274	                    )}
275	                  </div>
276	                  {(report.urgency_reason ?? report.risk_reason) && (
277	                    <p
278	                      className="text-[14px] leading-[1.6]"
279	                      style={{
280	                        color: riskColors.text,
281	                        fontFamily: "var(--font-dm-sans)",
282	                      }}
283	                    >
284	                      {report.urgency_reason ?? report.risk_reason}
285	                    </p>
286	                  )}
287	                </div>
288	              </div>
289	            </div>
290	          )}
291	
292	          {/* 9. Status Checks & Downloads */}
293	          {hasAvailabilitySection && (
294	            <section>
295	              <SectionLabel className="mb-3">
296	                {t("sr.detail.availabilityDownloads")}
297	              </SectionLabel>
